// Merge config from Master or Sheet reads (same pattern as WF1)
const webhookData = $('Webhook Trigger').first().json.body;

let config = {};
let competitors = [];

if (webhookData && webhookData.config) {
  // Master provided config + competitors
  config = webhookData.config;
  competitors = webhookData.competitors || [];
} else {
  // Standalone: build config from Sheet rows
  const konfigRows = $('Konfig aus Sheet lesen').all();
  for (const row of konfigRows) {
    const key = row.json['Einstellung'] || row.json['einstellung'];
    const val = row.json['Wert'] || row.json['wert'];
    if (key) config[key] = val;
  }

  // Parse competitors from Sheet
  const compRows = $('Wettbewerber aus Sheet lesen').all();
  competitors = compRows
    .map(r => r.json)
    .filter(c => String(c['Aktiv'] || c['aktiv']).toUpperCase() === 'TRUE');
}

// Parse active platforms
const activePlatforms = (config.active_platforms || '')
  .split(',')
  .map(p => p.trim().toLowerCase())
  .filter(p => p.length > 0);

// Calendar week
const now = new Date();
const startOfYear = new Date(now.getFullYear(), 0, 1);
const days = Math.floor((now - startOfYear) / (24 * 60 * 60 * 1000));
const calendarWeek = Math.ceil((days + startOfYear.getDay() + 1) / 7);

return [{
  json: {
    config,
    competitors,
    activePlatforms,
    calendarWeek,
    year: now.getFullYear(),
    projectName: config.project_name || 'unknown',
    brandName: config.brand_name || '',
    brandDescription: config.brand_description || '',
    branche: config.branche || config.brand_description || '',
    timestamp: now.toISOString()
  }
}];

// Creates 1 item per competitor-platform pair, filtered by active platforms.
// Max 3 competitors per platform x 6 platforms = 18 items.
const input = $input.first().json;
const { config, competitors, activePlatforms, calendarWeek, year, projectName, brandName, brandDescription, branche, timestamp } = input;

// Initialize global static data for result accumulation
const staticData = $getWorkflowStaticData('global');
staticData.results = [];
staticData.errors = [];
staticData.analyses = [];
staticData.startedAt = new Date().toISOString();

const items = [];

for (const comp of competitors) {
  const platform = (comp['Plattform'] || comp['plattform'] || '').toLowerCase();
  const name = comp['Name'] || comp['name'] || '';
  const url = comp['Account-URL'] || comp['account_url'] || comp['Account-Url'] || '';
  const accountId = comp['Account-ID'] || comp['account_id'] || '';

  // Skip if platform not active
  if (!activePlatforms.includes(platform)) continue;

  // Skip if missing essential data
  if (!name || !url) {
    staticData.errors.push({
      competitor: name || 'unbekannt',
      platform,
      error: 'Name oder Account-URL fehlt im Wettbewerber-Tab',
      timestamp: new Date().toISOString()
    });
    continue;
  }

  items.push({
    json: {
      competitorName: name,
      platform,
      accountUrl: url,
      accountId,
      calendarWeek,
      year,
      projectName,
      brandName,
      brandDescription,
      branche,
      config,
      timestamp
    }
  });
}

if (items.length === 0) {
  return [{ json: { _empty: true, _skip: true, message: 'Keine aktiven Wettbewerber gefunden — Workflow beendet', calendarWeek, year, projectName, timestamp } }];
}

return items;

const staticData = $getWorkflowStaticData('global');
const platformInfo = $('Plattform Switch').first().json;
const { competitorName, platform, accountUrl, calendarWeek, year, projectName } = platformInfo;

try {
  const items = $input.all();
  if (!items || items.length === 0 || items[0].json?.error) {
    throw new Error(items[0]?.json?.error || 'Keine Daten von Apify erhalten');
  }

  const posts = items.map(i => i.json).filter(p => p.likesCount !== undefined || p.likes !== undefined);
  if (posts.length === 0) throw new Error('Keine Posts gefunden');

  // Get follower count from parent data or first item
  const followers = posts[0]?.ownerFollowerCount || posts[0]?.followersCount || 0;

  // Sort by engagement (likes + comments)
  const sorted = [...posts].sort((a, b) => {
    const engA = (a.likesCount || a.likes || 0) + (a.commentsCount || a.comments || 0);
    const engB = (b.likesCount || b.likes || 0) + (b.commentsCount || b.comments || 0);
    return engB - engA;
  });

  // Top 3 posts
  const top3 = sorted.slice(0, 3).map(p => ({
    url: p.url || p.shortCode ? `https://instagram.com/p/${p.shortCode}` : '',
    text: (p.caption || '').substring(0, 500),
    likes: p.likesCount || p.likes || 0,
    comments: p.commentsCount || p.comments || 0,
    shares: 0,
    engagement: (p.likesCount || p.likes || 0) + (p.commentsCount || p.comments || 0),
    date: p.timestamp || p.takenAtTimestamp || '',
    type: p.videoViewCount ? 'video' : p.carouselMediaCount ? 'carousel' : 'image'
  }));

  // Extract comments from top posts (if available)
  const topComments = [];
  for (const p of sorted.slice(0, 3)) {
    const comments = p.latestComments || p.comments_list || [];
    for (const c of comments.slice(0, 7)) {
      topComments.push({
        text: c.text || c.comment || '',
        likes: c.likesCount || c.likes || 0,
        postUrl: p.url || ''
      });
    }
  }

  // Calculate averages
  const totalLikes = posts.reduce((s, p) => s + (p.likesCount || p.likes || 0), 0);
  const totalComments = posts.reduce((s, p) => s + (p.commentsCount || p.comments || 0), 0);
  const avgLikes = posts.length > 0 ? totalLikes / posts.length : 0;
  const avgComments = posts.length > 0 ? totalComments / posts.length : 0;
  const engagementRate = followers > 0 ? ((avgLikes + avgComments) / followers * 100) : 0;

  const result = {
    competitorName, platform, accountUrl, followers,
    postsScraped: posts.length,
    avgLikes: Math.round(avgLikes * 100) / 100,
    avgComments: Math.round(avgComments * 100) / 100,
    avgShares: 0,
    engagementRate: Math.round(engagementRate * 10000) / 10000,
    topPosts: top3,
    topComments: topComments.slice(0, 20),
    calendarWeek, year, projectName,
    status: 'ok'
  };

  return [{ json: result }];
} catch (error) {
  const errEntry = {
    competitorName, platform, calendarWeek, year, projectName,
    error: error.message, status: 'error'
  };
  staticData.errors.push(errEntry);
  return [{ json: errEntry }];
}

