const item = $input.first().json;
const promptData = $('Claude Prompt vorbereiten').first().json;

try {
  // The Anthropic node returns the response in various formats.
  // For resource:text, operation:message, the response content is typically in:
  // $json.content[0].text (API format) or $json.message or $json.text
  let responseText = '';
  if (item.content && Array.isArray(item.content)) {
    responseText = item.content.map(c => c.text || '').join('');
  } else if (item.message) {
    responseText = typeof item.message === 'string' ? item.message : JSON.stringify(item.message);
  } else if (item.text) {
    responseText = item.text;
  } else {
    // Fallback: stringify the whole response
    responseText = JSON.stringify(item);
  }

  // Try to parse as JSON
  // Remove potential markdown code blocks
  responseText = responseText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

  let analysis;
  try {
    analysis = JSON.parse(responseText);
  } catch (parseErr) {
    // If JSON parsing fails, wrap the text as analysis
    analysis = {
      staerken: responseText.substring(0, 500),
      engagement_treiber: '',
      community_sentiment: '',
      content_ideen: [],
      nicht_kopieren: ''
    };
  }

  // Extract content ideas
  const contentIdeas = analysis.content_ideen || analysis.contentIdeas || [];

  return [{
    json: {
      competitorName: promptData.competitorName,
      platform: promptData.platform,
      accountUrl: promptData.accountUrl,
      followers: promptData.followers,
